37	/**
38	 * Adds the base path to the input path, if it is not already present.
39	 */
40	export function withBase(input = "", base = ""): string {
41	  if (!base || base === "/") {
42	    return input;
43	  }
44	
45	  const _base = withoutTrailingSlash(base);
46	  if (input.startsWith(_base)) {
47	    return input;
48	  }
49	
50	  return joinURL(_base, input);
51	}
