// --------------------------
// Options
// --------------------------

export interface CircuitBreakerOptions {
  /** Consecutive failures required to open the circuit. Default is 5. */
  threshold?: number;

  /** Milliseconds to wait before allowing a half-open probe. Default is 30000. */
  cooldown?: number;

  /** Concurrent probe requests allowed while half-open. Default is 1. */
  halfOpenMaxRequests?: number;

  /** Response statuses counted as circuit failures. Default is [408, 409, 425, 429, 500, 502, 503, 504]. */
  failureStatusCodes?: number[];
}

export type CircuitBreakerOption = boolean | CircuitBreakerOptions;

export interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: number[];
}

const defaultFailureStatusCodes = Object.freeze([
  408, 409, 425, 429, 500, 502, 503, 504,
]);

export function resolveCircuitBreakerOptions(
  option: CircuitBreakerOption | undefined
): ResolvedCircuitBreakerOptions | undefined {
  if (!option) {
    return undefined;
  }
  const source = option === true ? {} : option;
  return {
    threshold: source.threshold ?? 5,
    cooldown: source.cooldown ?? 30_000,
    halfOpenMaxRequests: source.halfOpenMaxRequests ?? 1,
    failureStatusCodes: source.failureStatusCodes ?? [
      ...defaultFailureStatusCodes,
    ],
  };
}

// --------------------------
// Origin resolution
// --------------------------

export function resolveCircuitOrigin(
  request: FetchRequest
): string | undefined {
  try {
    if (typeof request === "string") {
      return new URL(request).origin;
    }
    if (request instanceof URL) {
      return request.origin;
    }
    if (typeof Request !== "undefined" && request instanceof Request) {
      return new URL(request.url).origin;
    }
  } catch {
    return undefined;
  }
  return undefined;
}

// --------------------------
// State
// --------------------------

type CircuitState = "closed" | "open" | "half-open";

interface CircuitEntry {
  state: CircuitState;
  failures: number;
  openedAt: number;
  halfOpenInFlight: number;
}

export type CircuitBreakerState = Map<string, CircuitEntry>;

export function createCircuitBreakerState(): CircuitBreakerState {
  return new Map();
}

export interface CircuitBreakerTicket {
  isProbe: boolean;
  settled: boolean;
  entry: CircuitEntry;
  config: ResolvedCircuitBreakerOptions;
}

function getOrCreateEntry(
  state: CircuitBreakerState,
  origin: string
): CircuitEntry {
  let entry = state.get(origin);
  if (!entry) {
    entry = { state: "closed", failures: 0, openedAt: 0, halfOpenInFlight: 0 };
    state.set(origin, entry);
  }
  return entry;
}

/**
 * Attempts to reserve a slot for a logical request against `origin`.
 * Returns `undefined` when the circuit is open (or the half-open probe
 * quota is exhausted), meaning the request must fail fast.
 */
export function acquireCircuitBreakerTicket(
  state: CircuitBreakerState,
  origin: string,
  config: ResolvedCircuitBreakerOptions,
  now: number
): CircuitBreakerTicket | undefined {
  const entry = getOrCreateEntry(state, origin);

  if (entry.state === "open" && now - entry.openedAt >= config.cooldown) {
    entry.state = "half-open";
    entry.halfOpenInFlight = 0;
  }

  if (entry.state === "open") {
    return undefined;
  }

  if (entry.state === "half-open") {
    if (entry.halfOpenInFlight >= config.halfOpenMaxRequests) {
      return undefined;
    }
    entry.halfOpenInFlight++;
    return { isProbe: true, settled: false, entry, config };
  }

  return { isProbe: false, settled: false, entry, config };
}

export function recordCircuitBreakerSuccess(
  ticket: CircuitBreakerTicket | undefined
): void {
  if (!ticket || ticket.settled) {
    return;
  }
  ticket.settled = true;
  const { entry } = ticket;
  if (ticket.isProbe) {
    entry.halfOpenInFlight = Math.max(0, entry.halfOpenInFlight - 1);
  }
  entry.failures = 0;
  if (entry.state === "half-open") {
    entry.state = "closed";
  }
}

export function recordCircuitBreakerFailure(
  ticket: CircuitBreakerTicket | undefined,
  now: number
): void {
  if (!ticket || ticket.settled) {
    return;
  }
  ticket.settled = true;
  const { entry, config } = ticket;
  if (ticket.isProbe) {
    entry.halfOpenInFlight = Math.max(0, entry.halfOpenInFlight - 1);
  }
  entry.failures++;
  if (entry.state === "half-open") {
    entry.state = "open";
    entry.openedAt = now;
  } else if (entry.state === "closed" && entry.failures >= config.threshold) {
    entry.state = "open";
    entry.openedAt = now;
  }
}

/**
 * Releases a probe slot without affecting the failure streak or state,
 * used for responses that are neither a listed failure status nor a thrown error.
 */
export function recordCircuitBreakerNeutral(
  ticket: CircuitBreakerTicket | undefined
): void {
  if (!ticket || ticket.settled) {
    return;
  }
  ticket.settled = true;
  const { entry } = ticket;
  if (ticket.isProbe) {
    entry.halfOpenInFlight = Math.max(0, entry.halfOpenInFlight - 1);
  }
}
