describe("circuit breaker", () => {
  afterEach(() => {
    vi.useRealTimers();
  });

  function jsonResponse(status: number) {
    return new Response("{}", {
      status,
      headers: { "content-type": "application/json" },
    });
  }

  // Each call consumes the next scripted result; the last result repeats.
  function mockFetch(...results: Array<number | Error>) {
    let call = 0;
    return vi.fn(async () => {
      const result = results[Math.min(call, results.length - 1)];
      call++;
      if (result instanceof Error) {
        throw result;
      }
      return jsonResponse(result);
    });
  }

  it("does not track or block when circuitBreaker is omitted or falsey", async () => {
    const fetchMock = mockFetch(500);
    const custom = createFetch({ fetch: fetchMock as any });
    for (let i = 0; i < 10; i++) {
      await custom("http://circuit-breaker.test/a", { retry: false }).catch(
        (error: any) => error
      );
    }
    expect(fetchMock).toHaveBeenCalledTimes(10);
  });

  it("opens the circuit after threshold consecutive failures, keyed by origin", async () => {
    const fetchMock = mockFetch(500);
    const custom = createFetch({ fetch: fetchMock as any });
    const circuitBreaker = { threshold: 3, cooldown: 30_000 };

    for (let i = 0; i < 3; i++) {
      await custom("http://circuit-breaker.test/a", {
        retry: false,
        circuitBreaker,
      }).catch((error: any) => error);
    }
    expect(fetchMock).toHaveBeenCalledTimes(3);

    // Different path, same origin -> still blocked (keyed by origin, not path).
    const error: any = await custom("http://circuit-breaker.test/b", {
      retry: false,
      circuitBreaker,
    }).catch((error_: any) => error_);

    expect(error.message).toContain("Circuit breaker is open");
    expect(fetchMock).toHaveBeenCalledTimes(3);
  });

